export const insCeoProfessionalQuestions: Question[] = [
  // Strategic Vision
  { id: 'ins-ceo-sv-01', profileId: 'insurance-ceo', categoryId: 'ins-ceo-professional', competencyId: 'ins-ceo-strategic-vision', type: 'scenario', content: { es: 'Usted es CEO de una aseguradora multirramo en Centroamérica con participación de mercado del 12%. En los últimos dos años, tres insurtechs respaldadas por capital de riesgo internacional han capturado el 8% del mercado de seguros personales con productos digitales de bajo costo. Su junta directiva le solicita un plan estratégico a 5 años para defender y expandir la posición competitiva.\nContexto: La penetración del seguro en la región es apenas del 2.5% del PIB. El 60% de su cartera actual proviene de seguros corporativos. Su red de agentes (400 personas) genera el 70% de la producción pero su productividad promedio ha caído 15% en dos años.', en: 'You are CEO of a multi-line insurer in Central America with 12% market share. Over the past two years, three venture-backed insurtechs have captured 8% of the personal lines market with low-cost digital products. Your board requests a 5-year strategic plan to defend and expand competitive positioning.\nContext: Insurance penetration in the region is only 2.5% of GDP. 60% of your current portfolio comes from corporate insurance. Your agent network (400 people) generates 70% of production but average productivity has declined 15% over two years.', fr: 'Vous êtes PDG d\'un assureur multi-branches en Amérique centrale avec 12% de part de marché. Trois insurtechs soutenues par du capital-risque ont capturé 8% du marché des assurances personnelles. Votre conseil demande un plan stratégique à 5 ans.\nContexte : La pénétration de l\'assurance dans la région est de seulement 2,5% du PIB. 60% de votre portefeuille provient des assurances entreprises. Votre réseau d\'agents (400 personnes) a vu sa productivité baisser de 15%.' }, rubric: { es: 'Evaluar: (1) Visión clara de posicionamiento competitivo diferenciado, (2) Estrategia de respuesta ante insurtechs (competir, colaborar o adquirir), (3) Plan de transformación del canal de distribución (agentes digitalizados + canales directos), (4) Estrategia de crecimiento en mercado subpenetrado, (5) Inversión en tecnología y capacidades digitales, (6) Métricas de éxito y governance del plan estratégico.', en: 'Evaluate: (1) Clear vision for differentiated competitive positioning, (2) Insurtech response strategy (compete, partner, or acquire), (3) Distribution channel transformation plan (digitized agents + direct channels), (4) Growth strategy in underpenetrated market, (5) Technology and digital capability investment, (6) Success metrics and strategic plan governance.', fr: 'Évaluer : (1) Vision claire de positionnement concurrentiel, (2) Stratégie de réponse aux insurtechs, (3) Plan de transformation de la distribution, (4) Stratégie de croissance dans un marché sous-pénétré, (5) Investissement technologique, (6) Métriques de succès et gouvernance du plan.' }, maxScore: 100, aiEvaluated: true, order: 1, isActive: true },
  // Regulatory Governance
  { id: 'ins-ceo-rg-01', profileId: 'insurance-ceo', categoryId: 'ins-ceo-professional', competencyId: 'ins-ceo-regulatory-governance', type: 'scenario', content: { es: 'La superintendencia de seguros ha iniciado una investigación sobre las prácticas de suscripción de su aseguradora en seguros de vida grupal, tras recibir denuncias de clientes sobre exclusiones no divulgadas adecuadamente. Simultáneamente, un medio de comunicación ha obtenido documentos internos que sugieren que el equipo comercial priorizó ventas sobre cumplimiento normativo.\nContexto: La aseguradora cotiza en bolsa. El regulador ha sancionado a dos competidores recientemente por prácticas similares con multas de USD 5 millones. Su director de cumplimiento renunció hace 3 meses y no ha sido reemplazado.', en: 'The insurance superintendent has initiated an investigation into your insurer\'s underwriting practices in group life insurance, following customer complaints about inadequately disclosed exclusions. Simultaneously, a media outlet has obtained internal documents suggesting the sales team prioritized sales over regulatory compliance.\nContext: The insurer is publicly listed. The regulator recently sanctioned two competitors for similar practices with USD 5 million fines. Your compliance director resigned 3 months ago and has not been replaced.', fr: 'La superintendance des assurances a ouvert une enquête sur les pratiques de souscription de votre assureur en assurance vie collective, suite à des plaintes de clients. Simultanément, un média a obtenu des documents internes suggérant que l\'équipe commerciale a privilégié les ventes sur la conformité.\nContexte : L\'assureur est coté en bourse. Le directeur de la conformité a démissionné il y a 3 mois.' }, rubric: { es: 'Evaluar: (1) Respuesta inmediata de crisis y gestión de comunicación, (2) Cooperación proactiva con el regulador, (3) Revisión interna exhaustiva de prácticas de suscripción, (4) Plan de remediación para clientes afectados, (5) Fortalecimiento de la función de cumplimiento y controles internos, (6) Rendición de cuentas y consecuencias para responsables.', en: 'Evaluate: (1) Immediate crisis response and communication management, (2) Proactive cooperation with regulator, (3) Thorough internal review of underwriting practices, (4) Remediation plan for affected customers, (5) Strengthening of compliance function and internal controls, (6) Accountability and consequences for responsible parties.', fr: 'Évaluer : (1) Réponse immédiate de crise et gestion de la communication, (2) Coopération proactive avec le régulateur, (3) Révision interne des pratiques de souscription, (4) Plan de remédiation, (5) Renforcement de la conformité, (6) Responsabilité et conséquences.' }, maxScore: 100, aiEvaluated: true, order: 2, isActive: true },
  // Product Portfolio
  { id: 'ins-ceo-pp-01', profileId: 'insurance-ceo', categoryId: 'ins-ceo-professional', competencyId: 'ins-ceo-product-portfolio', type: 'multiple-choice', content: { es: 'Su análisis de portafolio muestra que el 40% de los ingresos por primas proviene de seguros de automóviles con un ratio combinado del 105%, mientras que seguros de vida y salud representan solo el 20% con un ratio combinado del 85%. Los seguros patrimoniales (30%) operan a 95% y el 10% restante son microseguros experimentales a 115%. ¿Cuál es su estrategia de portafolio prioritaria?', en: 'Your portfolio analysis shows that 40% of premium income comes from auto insurance with a 105% combined ratio, while life and health represent only 20% at 85% combined ratio. Property insurance (30%) operates at 95% and the remaining 10% are experimental microinsurance at 115%. What is your priority portfolio strategy?', fr: 'Votre analyse de portefeuille montre que 40% des primes proviennent de l\'assurance automobile avec un ratio combiné de 105%, tandis que vie et santé représentent 20% à 85%. Les assurances patrimoniales (30%) opèrent à 95% et les 10% restants sont des micro-assurances expérimentales à 115%. Quelle est votre stratégie de portefeuille prioritaire ?' }, options: [{ id: 'a', text: { es: 'Ejecutar un plan integral: reestructurar suscripción y tarificación de autos para alcanzar 98% en 18 meses, invertir agresivamente en crecimiento de vida/salud con nuevos productos y canales, mantener patrimoniales como base estable, y pivotar microseguros hacia un modelo sostenible con alianzas fintech', en: 'Execute a comprehensive plan: restructure auto underwriting and pricing to reach 98% in 18 months, aggressively invest in life/health growth with new products and channels, maintain property as a stable base, and pivot microinsurance toward a sustainable model with fintech partnerships', fr: 'Exécuter un plan intégral : restructurer la souscription auto pour atteindre 98%, investir dans la croissance vie/santé, maintenir les assurances patrimoniales comme base stable, et pivoter les micro-assurances vers un modèle durable' }, value: 100 }, { id: 'b', text: { es: 'Abandonar inmediatamente el segmento de automóviles y microseguros para enfocarse en los ramos rentables', en: 'Immediately exit auto and microinsurance segments to focus on profitable lines', fr: 'Abandonner immédiatement l\'automobile et les micro-assurances pour se concentrer sur les branches rentables' }, value: 25 }, { id: 'c', text: { es: 'Aumentar primas de automóviles un 20% para mejorar el ratio combinado', en: 'Increase auto premiums by 20% to improve the combined ratio', fr: 'Augmenter les primes automobiles de 20% pour améliorer le ratio combiné' }, value: 35 }, { id: 'd', text: { es: 'Mantener la composición actual y esperar que el ciclo de mercado mejore la rentabilidad', en: 'Maintain the current composition and wait for the market cycle to improve profitability', fr: 'Maintenir la composition actuelle et attendre que le cycle du marché améliore la rentabilité' }, value: 10 }], maxScore: 100, aiEvaluated: false, order: 3, isActive: true },
  // Distribution Channels
  { id: 'ins-ceo-dc-01', profileId: 'insurance-ceo', categoryId: 'ins-ceo-professional', competencyId: 'ins-ceo-distribution-channels', type: 'multiple-choice', content: { es: 'Un banco líder en su mercado (8 millones de clientes) le propone una alianza exclusiva de bancaseguros por 10 años. Proyecta USD 50 millones anuales en primas, pero exige: comisiones del 45%, exclusividad total en el canal bancario, control sobre el diseño de productos, y marca blanca (productos con la marca del banco). Actualmente el canal bancario representa el 15% de sus primas. ¿Cómo procede?', en: 'A leading bank in your market (8 million customers) proposes an exclusive 10-year bancassurance alliance. It projects USD 50 million in annual premiums but demands: 45% commissions, total exclusivity in the banking channel, control over product design, and white-label products (bank-branded). Currently the banking channel represents 15% of your premiums. How do you proceed?', fr: 'Une banque leader sur votre marché (8 millions de clients) propose une alliance exclusive de bancassurance sur 10 ans. Elle projette 50 millions USD en primes annuelles mais exige : commissions de 45%, exclusivité totale, contrôle sur la conception des produits et marque blanche. Comment procédez-vous ?' }, options: [{ id: 'a', text: { es: 'Negociar condiciones equilibradas: comisiones escalonadas (35-40%) vinculadas a volumen, exclusividad parcial (solo productos diseñados conjuntamente), co-branding en lugar de marca blanca, cláusulas de desempeño mínimo y ventanas de salida cada 3 años', en: 'Negotiate balanced terms: tiered commissions (35-40%) linked to volume, partial exclusivity (only co-designed products), co-branding instead of white-label, minimum performance clauses and exit windows every 3 years', fr: 'Négocier des conditions équilibrées : commissions échelonnées (35-40%), exclusivité partielle, co-branding au lieu de marque blanche, clauses de performance minimum et fenêtres de sortie tous les 3 ans' }, value: 100 }, { id: 'b', text: { es: 'Aceptar todas las condiciones porque el volumen proyectado justifica las concesiones', en: 'Accept all conditions because the projected volume justifies the concessions', fr: 'Accepter toutes les conditions car le volume projeté justifie les concessions' }, value: 25 }, { id: 'c', text: { es: 'Rechazar la propuesta para proteger la independencia de marca y canales propios', en: 'Reject the proposal to protect brand independence and proprietary channels', fr: 'Rejeter la proposition pour protéger l\'indépendance de la marque et les canaux propres' }, value: 35 }, { id: 'd', text: { es: 'Aceptar pero planificar desarrollar canales digitales propios para reducir la dependencia en el futuro', en: 'Accept but plan to develop proprietary digital channels to reduce dependence in the future', fr: 'Accepter mais planifier le développement de canaux digitaux propres pour réduire la dépendance' }, value: 10 }], maxScore: 100, aiEvaluated: false, order: 4, isActive: true },
  // Reinsurance Strategy
  { id: 'ins-ceo-rs-01', profileId: 'insurance-ceo', categoryId: 'ins-ceo-professional', competencyId: 'ins-ceo-reinsurance-strategy', type: 'open-text', content: { es: 'Su aseguradora opera en el Caribe y Centroamérica, regiones altamente expuestas a huracanes y terremotos. El programa de reaseguro actual consume el 35% de las primas netas. Los reaseguradores han comunicado incrementos de tasas del 25-40% para la próxima renovación debido a las pérdidas catastróficas globales. Describa su estrategia integral de reaseguro y gestión de riesgo catastrófico para los próximos 3 años.', en: 'Your insurer operates in the Caribbean and Central America, regions highly exposed to hurricanes and earthquakes. The current reinsurance program consumes 35% of net premiums. Reinsurers have communicated rate increases of 25-40% for the next renewal due to global catastrophic losses. Describe your comprehensive reinsurance and catastrophe risk management strategy for the next 3 years.', fr: 'Votre assureur opère dans les Caraïbes et en Amérique centrale, régions très exposées aux ouragans et tremblements de terre. Le programme de réassurance actuel consomme 35% des primes nettes. Les réassureurs ont communiqué des hausses de tarifs de 25-40%. Décrivez votre stratégie intégrale de réassurance et de gestion du risque catastrophique pour les 3 prochaines années.' }, rubric: { es: 'Evaluar: (1) Optimización de la estructura de reaseguro (proporcional vs. no proporcional, capas, retención), (2) Diversificación de reaseguradores y acceso a mercados alternativos (ILS, cat bonds), (3) Mejora en modelación catastrófica y gestión de acumulación, (4) Estrategia de retención de riesgo calibrada a capital, (5) Negociación basada en datos y relación con reaseguradores, (6) Consideración de mecanismos de transferencia alternativos (cautivas, pools regionales).', en: 'Evaluate: (1) Reinsurance structure optimization (proportional vs. non-proportional, layers, retention), (2) Reinsurer diversification and access to alternative markets (ILS, cat bonds), (3) Improved catastrophe modeling and accumulation management, (4) Risk retention strategy calibrated to capital, (5) Data-driven negotiation and reinsurer relationship management, (6) Consideration of alternative transfer mechanisms (captives, regional pools).', fr: 'Évaluer : (1) Optimisation de la structure de réassurance, (2) Diversification des réassureurs et marchés alternatifs, (3) Modélisation catastrophique améliorée, (4) Stratégie de rétention calibrée au capital, (5) Négociation basée sur les données, (6) Mécanismes de transfert alternatifs.' }, maxScore: 100, aiEvaluated: true, order: 5, isActive: true },
  // Capital Management
  { id: 'ins-ceo-cm-01', profileId: 'insurance-ceo', categoryId: 'ins-ceo-professional', competencyId: 'ins-ceo-capital-management', type: 'scale', content: { es: '¿Qué nivel de experiencia tiene gestionando la estructura de capital, solvencia regulatoria y relaciones con calificadoras de riesgo en una compañía de seguros?', en: 'What level of experience do you have managing capital structure, regulatory solvency, and rating agency relationships in an insurance company?', fr: 'Quel niveau d\'expérience avez-vous dans la gestion de la structure du capital, la solvabilité réglementaire et les relations avec les agences de notation dans une compagnie d\'assurance ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Experiencia limitada en gestión de capital asegurador', en: 'Limited experience in insurance capital management', fr: 'Expérience limitée en gestion du capital d\'assurance' }, max: { es: 'Amplia experiencia liderando estrategia de capital y relaciones con calificadoras', en: 'Extensive experience leading capital strategy and rating agency relationships', fr: 'Vaste expérience dans la stratégie de capital et les relations avec les agences de notation' } }, maxScore: 100, aiEvaluated: false, order: 6, isActive: true },
];

export const insCeoSoftSkillsQuestions: Question[] = [
  // Board Management
  { id: 'ins-ceo-bm-01', profileId: 'insurance-ceo', categoryId: 'ins-ceo-soft-skills', competencyId: 'ins-ceo-board-management', type: 'scenario', content: { es: 'Su junta directiva está compuesta por 9 miembros: 3 representan al accionista mayoritario (un grupo financiero regional), 2 son accionistas minoritarios activistas que exigen mayor retorno a corto plazo, 2 son directores independientes con experiencia en seguros, y 2 son nuevos miembros sin experiencia en el sector. El accionista mayoritario quiere expandirse a seguros de salud (inversión de USD 30M), los minoritarios quieren vender la división de vida y distribuir dividendos extraordinarios, y los independientes creen que la prioridad es fortalecer tecnología.\nContexto: La próxima reunión de directorio es en 10 días. Debe presentar su recomendación estratégica.', en: 'Your board has 9 members: 3 represent the majority shareholder (a regional financial group), 2 are activist minority shareholders demanding higher short-term returns, 2 are independent directors with insurance experience, and 2 are new members without sector experience. The majority shareholder wants to expand into health insurance (USD 30M investment), minorities want to sell the life division and distribute extraordinary dividends, and independents believe the priority is strengthening technology.\nContext: The next board meeting is in 10 days. You must present your strategic recommendation.', fr: 'Votre conseil d\'administration compte 9 membres avec des intérêts divergents. L\'actionnaire majoritaire veut s\'étendre à l\'assurance santé, les minoritaires veulent vendre la division vie et distribuer des dividendes, et les indépendants croient que la priorité est la technologie.\nContexte : La prochaine réunion est dans 10 jours.' }, rubric: { es: 'Evaluar: (1) Capacidad de construir consenso entre facciones con intereses divergentes, (2) Preparación previa con reuniones individuales o de sub-grupos, (3) Propuesta que integre elementos de las distintas posiciones, (4) Uso de datos y análisis financiero para fundamentar la recomendación, (5) Manejo de la gobernanza corporativa y roles del CEO vs. directorio, (6) Habilidad para presentar opciones con riesgos y beneficios claros.', en: 'Evaluate: (1) Ability to build consensus among factions with divergent interests, (2) Pre-meeting preparation with individual or sub-group meetings, (3) Proposal that integrates elements from different positions, (4) Use of data and financial analysis to support the recommendation, (5) Management of corporate governance and CEO vs. board roles, (6) Ability to present options with clear risks and benefits.', fr: 'Évaluer : (1) Capacité à construire un consensus entre factions, (2) Préparation préalable avec réunions individuelles, (3) Proposition intégrant les différentes positions, (4) Utilisation de données et analyses financières, (5) Gestion de la gouvernance, (6) Présentation des options avec risques et bénéfices.' }, maxScore: 100, aiEvaluated: true, order: 1, isActive: true },
  // Industry Leadership
  { id: 'ins-ceo-il-01', profileId: 'insurance-ceo', categoryId: 'ins-ceo-soft-skills', competencyId: 'ins-ceo-industry-leadership', type: 'scenario', content: { es: 'Un terremoto devastador ha golpeado la región donde opera su aseguradora. Las pérdidas estimadas del sector alcanzan USD 800 millones. Su empresa tiene una exposición de USD 120 millones en siniestros, cubierta parcialmente por reaseguro. La asociación de aseguradores le solicita liderar la coordinación sectorial para la respuesta. Simultáneamente, el gobierno anuncia que evaluará la creación de un seguro obligatorio contra catástrofes y solicita la participación del sector privado.\nContexto: La opinión pública culpa a las aseguradoras por procesos de reclamación lentos. Solo el 20% de las propiedades afectadas tenían seguro.', en: 'A devastating earthquake has struck the region where your insurer operates. Estimated sector losses reach USD 800 million. Your company has USD 120 million in claims exposure, partially covered by reinsurance. The insurance association asks you to lead sectoral coordination for the response. Simultaneously, the government announces it will evaluate creating mandatory catastrophe insurance and requests private sector participation.\nContext: Public opinion blames insurers for slow claims processes. Only 20% of affected properties had insurance.', fr: 'Un tremblement de terre dévastateur a frappé votre région. Les pertes estimées du secteur atteignent 800 millions USD. L\'association des assureurs vous demande de coordonner la réponse sectorielle. Le gouvernement annonce l\'évaluation d\'une assurance catastrophe obligatoire.\nContexte : L\'opinion publique critique la lenteur des processus de réclamation. Seulement 20% des propriétés étaient assurées.' }, rubric: { es: 'Evaluar: (1) Liderazgo visible y empático en la crisis, (2) Coordinación efectiva con competidores para respuesta sectorial, (3) Aceleración del proceso de siniestros internamente, (4) Participación constructiva en el diseño de política pública, (5) Estrategia de comunicación que fortalezca la confianza en el sector, (6) Visión de largo plazo para cerrar la brecha de protección.', en: 'Evaluate: (1) Visible and empathetic crisis leadership, (2) Effective coordination with competitors for sectoral response, (3) Internal claims process acceleration, (4) Constructive participation in public policy design, (5) Communication strategy that strengthens sector trust, (6) Long-term vision to close the protection gap.', fr: 'Évaluer : (1) Leadership visible et empathique, (2) Coordination efficace avec les concurrents, (3) Accélération des processus de sinistres, (4) Participation constructive aux politiques publiques, (5) Stratégie de communication, (6) Vision à long terme pour combler le déficit de protection.' }, maxScore: 100, aiEvaluated: true, order: 2, isActive: true },
  // Crisis Management
  { id: 'ins-ceo-crm-01', profileId: 'insurance-ceo', categoryId: 'ins-ceo-soft-skills', competencyId: 'ins-ceo-crisis-management', type: 'multiple-choice', content: { es: 'Su aseguradora sufre un ciberataque que compromete datos personales de 200,000 asegurados (nombres, cédulas, historial médico). El equipo de TI confirma que la brecha lleva al menos 72 horas activa. El regulador exige notificación en 48 horas. Los medios aún no tienen conocimiento. ¿Cuál es su primera acción como CEO?', en: 'Your insurer suffers a cyberattack compromising personal data of 200,000 policyholders (names, IDs, medical history). The IT team confirms the breach has been active for at least 72 hours. The regulator requires notification within 48 hours. Media are not yet aware. What is your first action as CEO?', fr: 'Votre assureur subit une cyberattaque compromettant les données personnelles de 200 000 assurés. L\'équipe TI confirme que la brèche est active depuis au moins 72 heures. Le régulateur exige une notification sous 48 heures. Les médias ne sont pas encore au courant. Quelle est votre première action ?' }, options: [{ id: 'a', text: { es: 'Activar el plan de respuesta a incidentes: contener la brecha con equipos forenses, notificar al regulador dentro del plazo legal, preparar comunicación transparente a los asegurados afectados con medidas de protección ofrecidas, y convocar al comité de crisis con legal, comunicaciones, TI y operaciones', en: 'Activate the incident response plan: contain the breach with forensic teams, notify the regulator within the legal deadline, prepare transparent communication to affected policyholders with protection measures offered, and convene the crisis committee with legal, communications, IT, and operations', fr: 'Activer le plan de réponse aux incidents : contenir la brèche, notifier le régulateur dans les délais légaux, préparer une communication transparente aux assurés et convoquer le comité de crise' }, value: 100 }, { id: 'b', text: { es: 'Contener la brecha primero y evaluar el alcance antes de notificar a nadie', en: 'Contain the breach first and assess the scope before notifying anyone', fr: 'Contenir la brèche d\'abord et évaluer l\'ampleur avant de notifier quiconque' }, value: 35 }, { id: 'c', text: { es: 'Delegar la gestión completa al director de TI y al asesor legal', en: 'Delegate full management to the IT director and legal counsel', fr: 'Déléguer la gestion complète au directeur TI et au conseiller juridique' }, value: 10 }, { id: 'd', text: { es: 'Emitir inmediatamente un comunicado público antes de tener todos los detalles para mostrar transparencia', en: 'Immediately issue a public statement before having all details to demonstrate transparency', fr: 'Émettre immédiatement un communiqué public avant d\'avoir tous les détails pour montrer de la transparence' }, value: 25 }], maxScore: 100, aiEvaluated: false, order: 3, isActive: true },
  // Organizational Culture
  { id: 'ins-ceo-oc-01', profileId: 'insurance-ceo', categoryId: 'ins-ceo-soft-skills', competencyId: 'ins-ceo-organizational-culture', type: 'open-text', content: { es: 'Su aseguradora acaba de completar la adquisición de un competidor más pequeño especializado en seguros digitales. La empresa adquirida tiene una cultura ágil, informal y orientada a la innovación (120 empleados, promedio de edad 32 años). Su empresa tiene una cultura tradicional, jerárquica y orientada a procesos (800 empleados, promedio de edad 45 años). La integración cultural es el mayor riesgo identificado. Describa su estrategia para lograr una integración cultural exitosa que preserve lo mejor de ambas organizaciones.', en: 'Your insurer has just completed the acquisition of a smaller competitor specializing in digital insurance. The acquired company has an agile, informal, innovation-oriented culture (120 employees, average age 32). Your company has a traditional, hierarchical, process-oriented culture (800 employees, average age 45). Cultural integration is the top identified risk. Describe your strategy for achieving successful cultural integration that preserves the best of both organizations.', fr: 'Votre assureur vient d\'acquérir un concurrent plus petit spécialisé dans l\'assurance digitale. L\'entreprise acquise a une culture agile et informelle (120 employés, âge moyen 32 ans). Votre entreprise a une culture traditionnelle et hiérarchique (800 employés, âge moyen 45 ans). Décrivez votre stratégie d\'intégration culturelle.' }, rubric: { es: 'Evaluar: (1) Diagnóstico cultural de ambas organizaciones antes de diseñar la integración, (2) Definición de valores y comportamientos de la nueva cultura combinada, (3) Estrategia de retención del talento clave de la empresa adquirida, (4) Programas de integración (equipos mixtos, mentoría cruzada, proyectos conjuntos), (5) Comunicación transparente y frecuente durante la transición, (6) Métricas de engagement y mecanismos de retroalimentación.', en: 'Evaluate: (1) Cultural diagnosis of both organizations before designing integration, (2) Definition of values and behaviors for the new combined culture, (3) Key talent retention strategy for the acquired company, (4) Integration programs (mixed teams, cross-mentoring, joint projects), (5) Transparent and frequent communication during transition, (6) Engagement metrics and feedback mechanisms.', fr: 'Évaluer : (1) Diagnostic culturel des deux organisations, (2) Définition des valeurs de la nouvelle culture, (3) Stratégie de rétention du talent clé, (4) Programmes d\'intégration, (5) Communication transparente, (6) Métriques d\'engagement.' }, maxScore: 100, aiEvaluated: true, order: 4, isActive: true },
  // Board Management (scale)
  { id: 'ins-ceo-bm-02', profileId: 'insurance-ceo', categoryId: 'ins-ceo-soft-skills', competencyId: 'ins-ceo-board-management', type: 'scale', content: { es: '¿Qué tan efectivo se considera gestionando juntas directivas con múltiples grupos de interés y agendas divergentes en el sector asegurador?', en: 'How effective do you consider yourself at managing boards of directors with multiple stakeholder groups and divergent agendas in the insurance sector?', fr: 'Dans quelle mesure vous considérez-vous efficace pour gérer des conseils d\'administration avec des groupes d\'intérêts multiples et des agendas divergents dans le secteur de l\'assurance ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Experiencia limitada en gestión de juntas directivas', en: 'Limited board management experience', fr: 'Expérience limitée en gestion de conseils d\'administration' }, max: { es: 'Amplia experiencia liderando juntas directivas complejas con resultados comprobados', en: 'Extensive experience leading complex boards with proven results', fr: 'Vaste expérience de direction de conseils complexes avec résultats prouvés' } }, maxScore: 100, aiEvaluated: false, order: 5, isActive: true },
];

export const insCeoReadinessQuestions: Question[] = [
  // Insurtech
  { id: 'ins-ceo-it-01', profileId: 'insurance-ceo', categoryId: 'ins-ceo-readiness', competencyId: 'ins-ceo-insurtech', type: 'scenario', content: { es: 'Una insurtech líder en seguros paramétricos le propone una joint venture 50/50 para lanzar productos de seguro agrícola basados en índices climáticos satelitales en tres países de Centroamérica. La insurtech aporta la tecnología (plataforma, modelos de datos, APIs de datos satelitales) y su aseguradora aporta la licencia regulatoria, capital de respaldo y red de distribución rural. El mercado potencial es de 2 millones de pequeños agricultores actualmente sin seguro.\nContexto: El gobierno de uno de los países está subsidiando el 50% de la prima para seguros agrícolas. Sus sistemas actuales no soportan suscripción automática. Dos competidores están explorando propuestas similares.', en: 'A leading parametric insurance insurtech proposes a 50/50 joint venture to launch agricultural insurance products based on satellite climate indices in three Central American countries. The insurtech provides technology (platform, data models, satellite data APIs) and your insurer provides regulatory licensing, capital backing, and rural distribution network. The potential market is 2 million small farmers currently uninsured.\nContext: One country\'s government is subsidizing 50% of premiums for agricultural insurance. Your current systems do not support automated underwriting. Two competitors are exploring similar proposals.', fr: 'Une insurtech leader en assurance paramétrique propose une joint venture 50/50 pour lancer des produits d\'assurance agricole basés sur des indices climatiques satellitaires dans trois pays d\'Amérique centrale. L\'insurtech apporte la technologie et votre assureur apporte la licence réglementaire et le réseau de distribution rural.\nContexte : Un gouvernement subventionne 50% de la prime. Deux concurrents explorent des propositions similaires.' }, rubric: { es: 'Evaluar: (1) Análisis del modelo de negocio y viabilidad financiera de la JV, (2) Evaluación de riesgos tecnológicos y operacionales, (3) Estructura de gobernanza de la joint venture, (4) Estrategia de escalabilidad y expansión geográfica, (5) Aprovechamiento de subsidios gubernamentales y relaciones público-privadas, (6) Protección de propiedad intelectual y plan de salida.', en: 'Evaluate: (1) Business model analysis and JV financial viability, (2) Technology and operational risk assessment, (3) Joint venture governance structure, (4) Scalability and geographic expansion strategy, (5) Leveraging government subsidies and public-private relationships, (6) IP protection and exit plan.', fr: 'Évaluer : (1) Analyse du modèle d\'affaires et viabilité financière, (2) Évaluation des risques technologiques, (3) Structure de gouvernance de la JV, (4) Stratégie d\'expansion, (5) Subventions gouvernementales, (6) Protection de la PI et plan de sortie.' }, maxScore: 100, aiEvaluated: true, order: 1, isActive: true },
  // Climate/ESG
  { id: 'ins-ceo-esg-01', profileId: 'insurance-ceo', categoryId: 'ins-ceo-readiness', competencyId: 'ins-ceo-climate-esg', type: 'multiple-choice', content: { es: 'Inversionistas institucionales que representan el 30% del accionariado exigen que su aseguradora publique un reporte TCFD (Task Force on Climate-related Financial Disclosures) y establezca metas de descarbonización del portafolio de inversiones. Actualmente el 25% de sus inversiones están en sectores intensivos en carbono (petróleo, gas, minería). ¿Cuál es su enfoque?', en: 'Institutional investors representing 30% of shareholders demand that your insurer publish a TCFD report and establish decarbonization targets for the investment portfolio. Currently 25% of your investments are in carbon-intensive sectors (oil, gas, mining). What is your approach?', fr: 'Des investisseurs institutionnels représentant 30% de l\'actionnariat exigent que votre assureur publie un rapport TCFD et établisse des objectifs de décarbonation du portefeuille d\'investissements. Actuellement 25% de vos investissements sont dans des secteurs intensifs en carbone. Quelle est votre approche ?' }, options: [{ id: 'a', text: { es: 'Desarrollar una estrategia ESG integral: publicar TCFD con escenarios climáticos, establecer una hoja de ruta de descarbonización gradual con metas intermedias verificables, integrar criterios ESG en suscripción e inversiones, y crear productos de seguro verde para nuevos mercados', en: 'Develop a comprehensive ESG strategy: publish TCFD with climate scenarios, establish a gradual decarbonization roadmap with verifiable intermediate targets, integrate ESG criteria into underwriting and investments, and create green insurance products for new markets', fr: 'Développer une stratégie ESG intégrale : publier le TCFD avec des scénarios climatiques, établir une feuille de route de décarbonation graduelle, intégrer des critères ESG dans la souscription et les investissements, et créer des produits d\'assurance verte' }, value: 100 }, { id: 'b', text: { es: 'Publicar el reporte TCFD pero sin comprometerse con metas específicas de descarbonización', en: 'Publish the TCFD report but without committing to specific decarbonization targets', fr: 'Publier le rapport TCFD mais sans s\'engager sur des objectifs spécifiques de décarbonation' }, value: 35 }, { id: 'c', text: { es: 'Desinvertir inmediatamente de todos los sectores intensivos en carbono para satisfacer a los inversionistas', en: 'Immediately divest from all carbon-intensive sectors to satisfy investors', fr: 'Se désengager immédiatement de tous les secteurs intensifs en carbone' }, value: 25 }, { id: 'd', text: { es: 'Argumentar que las regulaciones locales no exigen TCFD y que el foco debe ser la rentabilidad', en: 'Argue that local regulations do not require TCFD and the focus should be profitability', fr: 'Argumenter que les réglementations locales n\'exigent pas le TCFD et que le focus doit être la rentabilité' }, value: 10 }], maxScore: 100, aiEvaluated: false, order: 2, isActive: true },
  // Data-Driven Decisions
  { id: 'ins-ceo-dd-01', profileId: 'insurance-ceo', categoryId: 'ins-ceo-readiness', competencyId: 'ins-ceo-data-driven', type: 'open-text', content: { es: 'Describa cómo transformaría la cultura de toma de decisiones de su aseguradora de un enfoque basado en experiencia e intuición hacia un modelo data-driven. Considere que actualmente la empresa tiene datos dispersos en 12 sistemas diferentes, los reportes se generan manualmente en Excel, y menos del 10% de los gerentes utilizan analítica avanzada para tomar decisiones.', en: 'Describe how you would transform your insurer\'s decision-making culture from an experience-and-intuition-based approach to a data-driven model. Consider that currently the company has data scattered across 12 different systems, reports are manually generated in Excel, and less than 10% of managers use advanced analytics for decision-making.', fr: 'Décrivez comment vous transformeriez la culture de prise de décision de votre assureur d\'une approche basée sur l\'expérience et l\'intuition vers un modèle data-driven. Actuellement, les données sont dispersées dans 12 systèmes différents, les rapports sont générés manuellement dans Excel, et moins de 10% des managers utilisent l\'analytique avancée.' }, rubric: { es: 'Evaluar: (1) Estrategia de data governance y consolidación de datos (data lake/warehouse), (2) Inversión en capacidades de BI y analytics, (3) Programa de alfabetización de datos para todos los niveles, (4) Casos de uso prioritarios con impacto medible (pricing, siniestros, fraude, retención), (5) Cambio cultural y liderazgo con el ejemplo, (6) Estructura organizacional (CDO, equipos de datos, data champions por área).', en: 'Evaluate: (1) Data governance and consolidation strategy (data lake/warehouse), (2) Investment in BI and analytics capabilities, (3) Data literacy program for all levels, (4) Priority use cases with measurable impact (pricing, claims, fraud, retention), (5) Cultural change and leading by example, (6) Organizational structure (CDO, data teams, area data champions).', fr: 'Évaluer : (1) Stratégie de gouvernance des données et consolidation, (2) Investissement en capacités BI et analytique, (3) Programme d\'alphabétisation des données, (4) Cas d\'utilisation prioritaires, (5) Changement culturel et leadership par l\'exemple, (6) Structure organisationnelle.' }, maxScore: 100, aiEvaluated: true, order: 3, isActive: true },
  // Insurtech (scale)
  { id: 'ins-ceo-it-02', profileId: 'insurance-ceo', categoryId: 'ins-ceo-readiness', competencyId: 'ins-ceo-insurtech', type: 'scale', content: { es: '¿Qué tan preparado se considera para liderar la transformación digital integral de una compañía de seguros, incluyendo la adopción de insurtechs, inteligencia artificial y modelos de negocio digitales?', en: 'How prepared do you consider yourself to lead the comprehensive digital transformation of an insurance company, including insurtech adoption, artificial intelligence, and digital business models?', fr: 'Dans quelle mesure vous considérez-vous prêt à diriger la transformation digitale intégrale d\'une compagnie d\'assurance, y compris l\'adoption d\'insurtechs, l\'intelligence artificielle et les modèles d\'affaires numériques ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Conocimiento básico de tendencias digitales en seguros', en: 'Basic knowledge of digital trends in insurance', fr: 'Connaissance de base des tendances numériques en assurance' }, max: { es: 'He liderado transformaciones digitales exitosas en el sector asegurador', en: 'I have led successful digital transformations in the insurance sector', fr: 'J\'ai dirigé des transformations numériques réussies dans le secteur de l\'assurance' } }, maxScore: 100, aiEvaluated: false, order: 4, isActive: true },
];

// ============================================================================
// INSURANCE BROKER CEO QUESTIONS
// ============================================================================

export const insBrokerProfessionalQuestions: Question[] = [
  // Brokerage Strategy
  { id: 'ins-broker-bs-01', profileId: 'insurance-broker-ceo', categoryId: 'ins-broker-professional', competencyId: 'ins-broker-brokerage-strategy', type: 'scenario', content: { es: 'Usted dirige un corredor de seguros mediano con USD 25 millones en comisiones anuales, 45 ejecutivos comerciales y presencia en dos países centroamericanos. Un corredor internacional con operaciones en 30 países le propone una fusión: absorbería su operación, retendría al equipo clave por 3 años, y le ofrecería ser CEO regional para Centroamérica y Caribe. Alternativamente, un fondo de private equity le ofrece invertir USD 15 millones para financiar su plan de crecimiento orgánico a cambio del 40% de la empresa.\nContexto: Su tasa de crecimiento ha sido del 8% anual vs. 12% del mercado. La concentración de ingresos es alta: los 10 principales clientes representan el 55% de las comisiones. Tres ejecutivos senior clave han recibido ofertas de competidores.', en: 'You lead a mid-size insurance broker with USD 25 million in annual commissions, 45 commercial executives, and presence in two Central American countries. An international broker with operations in 30 countries proposes a merger: it would absorb your operation, retain key team for 3 years, and offer you the role of regional CEO for Central America and the Caribbean. Alternatively, a private equity fund offers to invest USD 15 million for your organic growth plan in exchange for 40% of the company.\nContext: Your growth rate has been 8% annually vs. 12% for the market. Revenue concentration is high: top 10 clients represent 55% of commissions. Three key senior executives have received competitor offers.', fr: 'Vous dirigez un courtier d\'assurance moyen avec 25 millions USD de commissions annuelles. Un courtier international propose une fusion et un fonds de PE offre d\'investir 15 millions USD pour 40% de l\'entreprise.\nContexte : Votre taux de croissance est de 8% vs. 12% du marché. Les 10 principaux clients représentent 55% des commissions. Trois cadres clés ont reçu des offres de concurrents.' }, rubric: { es: 'Evaluar: (1) Análisis riguroso de ambas opciones con métricas financieras (valoración, retorno para accionistas, sinergias), (2) Evaluación de fit cultural y operacional con el socio potencial, (3) Estrategia de retención del talento clave independientemente de la decisión, (4) Plan de diversificación de la base de clientes, (5) Consideración de la visión a largo plazo vs. liquidez inmediata, (6) Negociación de términos protectores (gobernanza, cláusulas de no competencia, earn-outs).', en: 'Evaluate: (1) Rigorous analysis of both options with financial metrics (valuation, shareholder return, synergies), (2) Cultural and operational fit assessment with potential partner, (3) Key talent retention strategy regardless of decision, (4) Client base diversification plan, (5) Long-term vision vs. immediate liquidity consideration, (6) Protective term negotiation (governance, non-compete, earn-outs).', fr: 'Évaluer : (1) Analyse rigoureuse des deux options avec métriques financières, (2) Évaluation du fit culturel et opérationnel, (3) Stratégie de rétention du talent, (4) Plan de diversification des clients, (5) Vision à long terme vs. liquidité, (6) Négociation de termes protecteurs.' }, maxScore: 100, aiEvaluated: true, order: 1, isActive: true },
  // Client Portfolio
  { id: 'ins-broker-cp-01', profileId: 'insurance-broker-ceo', categoryId: 'ins-broker-professional', competencyId: 'ins-broker-client-portfolio', type: 'scenario', content: { es: 'Su cliente corporativo más grande (genera el 18% de sus comisiones totales) le informa que ha decidido consolidar todos sus programas de seguros con un solo corredor global. Actualmente usted maneja los seguros locales de la empresa (patrimoniales, responsabilidad civil, autos de flota), pero el nuevo esquema exige capacidades en 15 países, gestión centralizada de programas internacionales, y un portal tecnológico de gestión de pólizas que usted no tiene. La decisión final se tomará en 90 días.\nContexto: El competidor principal es un corredor global con oficinas en los 15 países requeridos. Usted tiene alianzas informales con corredores locales en solo 6 de esos países.', en: 'Your largest corporate client (generating 18% of total commissions) informs you they have decided to consolidate all insurance programs with a single global broker. You currently handle the company\'s local insurance (property, liability, fleet auto), but the new scheme requires capabilities in 15 countries, centralized international program management, and a policy management tech portal you do not have. The final decision will be made in 90 days.\nContext: The main competitor is a global broker with offices in all 15 required countries. You have informal alliances with local brokers in only 6 of those countries.', fr: 'Votre plus grand client corporatif (18% des commissions) vous informe qu\'il va consolider tous ses programmes d\'assurance avec un seul courtier global. Vous n\'avez des alliances que dans 6 des 15 pays requis. La décision finale sera prise dans 90 jours.' }, rubric: { es: 'Evaluar: (1) Estrategia de retención inmediata (propuesta de valor diferenciada), (2) Formalización rápida de alianzas o afiliación a una red global de corredores, (3) Solución tecnológica (asociación con plataforma, desarrollo acelerado o adquisición), (4) Propuesta competitiva con ventajas locales vs. global, (5) Plan de contingencia si pierde la cuenta (diversificación), (6) Aprendizaje estratégico para fortalecer capacidades a largo plazo.', en: 'Evaluate: (1) Immediate retention strategy (differentiated value proposition), (2) Rapid alliance formalization or affiliation with a global broker network, (3) Technology solution (platform partnership, accelerated development, or acquisition), (4) Competitive proposal leveraging local advantages vs. global, (5) Contingency plan if the account is lost (diversification), (6) Strategic learning to strengthen long-term capabilities.', fr: 'Évaluer : (1) Stratégie de rétention immédiate, (2) Formalisation rapide d\'alliances ou affiliation à un réseau global, (3) Solution technologique, (4) Proposition compétitive, (5) Plan de contingence, (6) Apprentissage stratégique.' }, maxScore: 100, aiEvaluated: true, order: 2, isActive: true },
  // Carrier Relationships
  { id: 'ins-broker-cr-01', profileId: 'insurance-broker-ceo', categoryId: 'ins-broker-professional', competencyId: 'ins-broker-carrier-relationships', type: 'multiple-choice', content: { es: 'Su correduría trabaja con 12 aseguradoras, pero el 65% de la producción se coloca en solo 3 de ellas. Una de estas tres aseguradoras principales (30% de su producción) le comunica que reducirá las comisiones un 20% y eliminará los bonos de producción a partir del próximo trimestre. ¿Cómo responde estratégicamente?', en: 'Your brokerage works with 12 insurers, but 65% of production is placed with only 3 of them. One of these three main insurers (30% of your production) communicates it will reduce commissions by 20% and eliminate production bonuses starting next quarter. How do you respond strategically?', fr: 'Votre courtage travaille avec 12 assureurs, mais 65% de la production est placée auprès de seulement 3 d\'entre eux. L\'un de ces trois assureurs principaux (30% de votre production) réduit les commissions de 20% et élimine les bonus de production. Comment répondez-vous ?' }, options: [{ id: 'a', text: { es: 'Desarrollar un plan de diversificación gradual: negociar condiciones mejoradas con las otras 9 aseguradoras, crear capacidad técnica para redirigir negocios selectivamente, y simultáneamente negociar con la aseguradora basándose en datos de siniestralidad favorable y valor de la relación para mitigar el recorte', en: 'Develop a gradual diversification plan: negotiate improved terms with the other 9 insurers, build technical capacity to selectively redirect business, and simultaneously negotiate with the insurer based on favorable loss ratio data and relationship value to mitigate the cut', fr: 'Développer un plan de diversification graduel : négocier avec les 9 autres assureurs, créer la capacité de rediriger les affaires sélectivement, et négocier simultanément avec l\'assureur basé sur les données de sinistralité' }, value: 100 }, { id: 'b', text: { es: 'Amenazar con trasladar toda la producción a competidores si no retiran los recortes', en: 'Threaten to move all production to competitors if they do not withdraw the cuts', fr: 'Menacer de transférer toute la production aux concurrents s\'ils ne retirent pas les réductions' }, value: 25 }, { id: 'c', text: { es: 'Aceptar los nuevos términos y compensar con mayor volumen de producción', en: 'Accept the new terms and compensate with higher production volume', fr: 'Accepter les nouveaux termes et compenser par un volume de production plus élevé' }, value: 35 }, { id: 'd', text: { es: 'Trasladar inmediatamente todo el negocio de esa aseguradora a otros mercados', en: 'Immediately transfer all business from that insurer to other markets', fr: 'Transférer immédiatement toutes les affaires de cet assureur vers d\'autres marchés' }, value: 10 }], maxScore: 100, aiEvaluated: false, order: 3, isActive: true },
  // Market Placement
  { id: 'ins-broker-mp-01', profileId: 'insurance-broker-ceo', categoryId: 'ins-broker-professional', competencyId: 'ins-broker-market-placement', type: 'multiple-choice', content: { es: 'Un cliente industrial le solicita colocar un programa de seguros complejo: responsabilidad civil ambiental, interrupción de negocio contingente, y cyber para su cadena de suministro en 5 países latinoamericanos. Ninguna aseguradora local ofrece cobertura para los tres riesgos conjuntamente. El mercado de Londres y Bermuda tienen capacidad pero el cliente necesita emisión local de pólizas por requisitos regulatorios. ¿Cuál es su estrategia de colocación?', en: 'An industrial client asks you to place a complex insurance program: environmental liability, contingent business interruption, and cyber for their supply chain across 5 Latin American countries. No local insurer offers coverage for all three risks jointly. London and Bermuda markets have capacity but the client needs local policy issuance for regulatory requirements. What is your placement strategy?', fr: 'Un client industriel vous demande de placer un programme complexe : responsabilité environnementale, interruption d\'activité contingente et cyber pour sa chaîne d\'approvisionnement dans 5 pays. Aucun assureur local ne couvre les trois risques conjointement. Les marchés de Londres et Bermudes ont de la capacité mais le client a besoin d\'émission locale. Quelle est votre stratégie ?' }, options: [{ id: 'a', text: { es: 'Diseñar un programa fronting: negociar con mercados de Londres/Bermuda como líderes de capacidad, estructurar fronting con aseguradoras locales en cada país para emisión de pólizas, y crear un manuscrito que armonice coberturas con las regulaciones de los 5 países', en: 'Design a fronting program: negotiate with London/Bermuda markets as capacity leaders, structure fronting arrangements with local insurers in each country for policy issuance, and create a manuscript that harmonizes coverages with regulations in all 5 countries', fr: 'Concevoir un programme de fronting : négocier avec les marchés de Londres/Bermudes, structurer le fronting avec des assureurs locaux dans chaque pays et créer un manuscrit harmonisant les couvertures avec les réglementations des 5 pays' }, value: 100 }, { id: 'b', text: { es: 'Dividir el programa en tres pólizas separadas y colocar cada una con el especialista local más competitivo', en: 'Split the program into three separate policies and place each with the most competitive local specialist', fr: 'Diviser le programme en trois polices séparées et placer chacune avec le spécialiste local le plus compétitif' }, value: 35 }, { id: 'c', text: { es: 'Informar al cliente que el programa es demasiado complejo para el mercado local y recomendar contratar un corredor global', en: 'Inform the client that the program is too complex for the local market and recommend hiring a global broker', fr: 'Informer le client que le programme est trop complexe pour le marché local et recommander un courtier global' }, value: 10 }, { id: 'd', text: { es: 'Colocar todo directamente en Lloyd\'s de Londres sin fronting local y gestionar el riesgo regulatorio', en: 'Place everything directly at Lloyd\'s of London without local fronting and manage the regulatory risk', fr: 'Placer tout directement au Lloyd\'s de Londres sans fronting local et gérer le risque réglementaire' }, value: 25 }], maxScore: 100, aiEvaluated: false, order: 4, isActive: true },
  // Revenue Diversification
  { id: 'ins-broker-rd-01', profileId: 'insurance-broker-ceo', categoryId: 'ins-broker-professional', competencyId: 'ins-broker-revenue-diversification', type: 'open-text', content: { es: 'Las comisiones tradicionales de intermediación están bajo presión: los reguladores en su mercado evalúan exigir transparencia total de comisiones al cliente, las aseguradoras buscan canales directos, y los clientes corporativos grandes están contratando gestores de riesgos internos. Describa su estrategia para diversificar los ingresos de su correduría más allá de las comisiones de intermediación tradicionales en los próximos 3 años.', en: 'Traditional intermediation commissions are under pressure: regulators in your market are evaluating full commission transparency to clients, insurers are pursuing direct channels, and large corporate clients are hiring internal risk managers. Describe your strategy to diversify your brokerage\'s revenue beyond traditional intermediation commissions over the next 3 years.', fr: 'Les commissions traditionnelles d\'intermédiation sont sous pression : les régulateurs évaluent la transparence totale des commissions, les assureurs développent des canaux directs, et les grands clients embauchent des gestionnaires de risques internes. Décrivez votre stratégie de diversification des revenus pour les 3 prochaines années.' }, rubric: { es: 'Evaluar: (1) Desarrollo de servicios de consultoría en gestión de riesgos (fee-based), (2) Creación de capacidad de administración de programas (TPA), (3) Servicios tecnológicos (plataformas de gestión de pólizas para clientes), (4) Modelo de honorarios por asesoría vs. comisiones, (5) Expansión a líneas de beneficios para empleados y wellness corporativo, (6) Alianzas estratégicas o adquisiciones para ampliar el portafolio de servicios.', en: 'Evaluate: (1) Risk management consulting services development (fee-based), (2) Program administration capability (TPA), (3) Technology services (policy management platforms for clients), (4) Advisory fee model vs. commissions, (5) Expansion to employee benefits and corporate wellness, (6) Strategic alliances or acquisitions to broaden service portfolio.', fr: 'Évaluer : (1) Développement de services de conseil en gestion des risques, (2) Capacité d\'administration de programmes, (3) Services technologiques, (4) Modèle d\'honoraires, (5) Expansion aux avantages sociaux, (6) Alliances stratégiques ou acquisitions.' }, maxScore: 100, aiEvaluated: true, order: 5, isActive: true },
  // Compliance
  { id: 'ins-broker-co-01', profileId: 'insurance-broker-ceo', categoryId: 'ins-broker-professional', competencyId: 'ins-broker-compliance', type: 'scale', content: { es: '¿Qué nivel de experiencia tiene implementando y gestionando programas de cumplimiento regulatorio, prevención de lavado de activos y conflictos de interés en una correduría de seguros?', en: 'What level of experience do you have implementing and managing regulatory compliance programs, anti-money laundering, and conflict of interest management in an insurance brokerage?', fr: 'Quel niveau d\'expérience avez-vous dans la mise en œuvre de programmes de conformité réglementaire, de lutte contre le blanchiment d\'argent et de gestion des conflits d\'intérêts dans un courtage d\'assurance ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Conocimiento básico de regulación de intermediarios', en: 'Basic knowledge of intermediary regulation', fr: 'Connaissance de base de la réglementation des intermédiaires' }, max: { es: 'He diseñado e implementado programas de cumplimiento integrales con éxito comprobado', en: 'I have designed and implemented comprehensive compliance programs with proven success', fr: 'J\'ai conçu et mis en œuvre des programmes de conformité complets avec succès prouvé' } }, maxScore: 100, aiEvaluated: false, order: 6, isActive: true },
];

export const insBrokerSoftSkillsQuestions: Question[] = [
  // Client Advisory
  { id: 'ins-broker-ca-01', profileId: 'insurance-broker-ceo', categoryId: 'ins-broker-soft-skills', competencyId: 'ins-broker-client-advisory', type: 'scenario', content: { es: 'El CEO de una empresa de energía renovable (cliente que genera USD 800,000 en comisiones anuales) le solicita una reunión urgente. Su empresa está por cerrar una emisión de bonos verdes por USD 200 millones y los inversionistas exigen que demuestre cobertura integral de riesgos ESG. El cliente necesita en 15 días un informe que demuestre: (1) cobertura de riesgos ambientales y de responsabilidad civil, (2) seguro contra interrupción por eventos climáticos extremos, (3) cobertura para la cadena de suministro de paneles solares, y (4) seguro de directores y oficiales con extensión ESG.\nContexto: Su equipo no tiene especialista en riesgos ESG. El mercado local tiene capacidad limitada para estos productos.', en: 'The CEO of a renewable energy company (a client generating USD 800,000 in annual commissions) requests an urgent meeting. The company is about to close a USD 200 million green bond issuance and investors require proof of comprehensive ESG risk coverage. The client needs within 15 days a report demonstrating: (1) environmental and liability risk coverage, (2) insurance against extreme climate event interruption, (3) supply chain coverage for solar panels, and (4) D&O insurance with ESG extension.\nContext: Your team lacks an ESG risk specialist. The local market has limited capacity for these products.', fr: 'Le PDG d\'une entreprise d\'énergie renouvelable (800 000 USD de commissions annuelles) demande une réunion urgente. Son entreprise va émettre des obligations vertes de 200 millions USD et les investisseurs exigent une couverture intégrale des risques ESG sous 15 jours.\nContexte : Votre équipe n\'a pas de spécialiste en risques ESG. Le marché local a une capacité limitée.' }, rubric: { es: 'Evaluar: (1) Capacidad de respuesta rápida y movilización de recursos especializados (consultores externos, corresponsales internacionales), (2) Comprensión de los requerimientos de riesgo ESG para emisiones de bonos verdes, (3) Diseño de programa de cobertura integral con acceso a mercados internacionales, (4) Posicionamiento como asesor estratégico de riesgos más allá de la intermediación, (5) Gestión del timeline con hitos claros, (6) Oportunidad de negocio a largo plazo (especialización en sector energía limpia).', en: 'Evaluate: (1) Rapid response and specialized resource mobilization (external consultants, international correspondents), (2) Understanding of ESG risk requirements for green bond issuances, (3) Comprehensive coverage program design accessing international markets, (4) Strategic risk advisor positioning beyond intermediation, (5) Timeline management with clear milestones, (6) Long-term business opportunity (clean energy sector specialization).', fr: 'Évaluer : (1) Capacité de réponse rapide et mobilisation de ressources spécialisées, (2) Compréhension des exigences ESG, (3) Conception de programme de couverture intégral, (4) Positionnement comme conseiller stratégique, (5) Gestion du calendrier, (6) Opportunité commerciale à long terme.' }, maxScore: 100, aiEvaluated: true, order: 1, isActive: true },
  // Team Building
  { id: 'ins-broker-tb-01', profileId: 'insurance-broker-ceo', categoryId: 'ins-broker-soft-skills', competencyId: 'ins-broker-team-building', type: 'multiple-choice', content: { es: 'Su correduría ha crecido de 25 a 80 empleados en 3 años. La cultura informal que funcionaba cuando eran pocos ahora genera problemas: los ejecutivos senior se quejan de falta de estructura, los nuevos empleados no entienden la visión del negocio, y la rotación voluntaria ha subido al 25% anual. ¿Cuál es su prioridad como CEO?', en: 'Your brokerage has grown from 25 to 80 employees in 3 years. The informal culture that worked when the team was small now creates problems: senior executives complain about lack of structure, new employees do not understand the business vision, and voluntary turnover has risen to 25% annually. What is your priority as CEO?', fr: 'Votre courtage est passé de 25 à 80 employés en 3 ans. La culture informelle génère maintenant des problèmes : les cadres se plaignent du manque de structure, les nouveaux ne comprennent pas la vision, et la rotation a atteint 25%. Quelle est votre priorité ?' }, options: [{ id: 'a', text: { es: 'Implementar un programa integral de desarrollo organizacional: codificar la cultura y valores, crear estructura de liderazgo intermedio con roles claros, establecer planes de carrera y compensación competitivos, e implementar onboarding estructurado y mentoring para nuevos empleados', en: 'Implement a comprehensive organizational development program: codify culture and values, create middle leadership structure with clear roles, establish competitive career plans and compensation, and implement structured onboarding and mentoring for new employees', fr: 'Implémenter un programme intégral de développement organisationnel : codifier la culture et les valeurs, créer une structure de leadership intermédiaire, établir des plans de carrière et un onboarding structuré' }, value: 100 }, { id: 'b', text: { es: 'Contratar un director de recursos humanos y delegar completamente la solución', en: 'Hire an HR director and fully delegate the solution', fr: 'Embaucher un directeur RH et déléguer complètement la solution' }, value: 25 }, { id: 'c', text: { es: 'Aumentar salarios un 15% para reducir la rotación', en: 'Increase salaries by 15% to reduce turnover', fr: 'Augmenter les salaires de 15% pour réduire la rotation' }, value: 35 }, { id: 'd', text: { es: 'Reducir el ritmo de crecimiento hasta que la cultura se estabilice', en: 'Reduce the growth pace until the culture stabilizes', fr: 'Réduire le rythme de croissance jusqu\'à ce que la culture se stabilise' }, value: 10 }], maxScore: 100, aiEvaluated: false, order: 2, isActive: true },
  // Negotiation
  { id: 'ins-broker-ng-01', profileId: 'insurance-broker-ceo', categoryId: 'ins-broker-soft-skills', competencyId: 'ins-broker-negotiation', type: 'multiple-choice', content: { es: 'Está renovando el programa de seguros más grande de su cartera (USD 4 millones en primas, USD 600,000 en comisiones). La aseguradora líder propone un incremento de prima del 35% debido a dos siniestros grandes en el último año (ratio de siniestralidad del 120%). El cliente le dice que si la renovación supera el 15% de aumento, sacará el programa a licitación con otros corredores. ¿Cuál es su estrategia?', en: 'You are renewing your portfolio\'s largest insurance program (USD 4 million in premiums, USD 600,000 in commissions). The lead insurer proposes a 35% premium increase due to two large claims last year (120% loss ratio). The client says if the renewal exceeds a 15% increase, they will put the program out to bid with other brokers. What is your strategy?', fr: 'Vous renouvelez le plus grand programme de votre portefeuille (4 millions USD en primes, 600 000 USD en commissions). L\'assureur propose une hausse de 35% due à une sinistralité de 120%. Le client menace de lancer un appel d\'offres si l\'augmentation dépasse 15%. Quelle est votre stratégie ?' }, options: [{ id: 'a', text: { es: 'Desarrollar una propuesta técnica integral: reestructurar el programa (aumentar retención, modificar capas, agregar coaseguradoras), presentar al cliente un plan de mejora de riesgos para reducir la siniestralidad futura, negociar con la aseguradora un incremento escalonado vinculado a mejoras de riesgo, y cotizar el mercado alternativo como apalancamiento', en: 'Develop a comprehensive technical proposal: restructure the program (increase retention, modify layers, add co-insurers), present the client with a risk improvement plan to reduce future loss ratio, negotiate a phased increase with the insurer tied to risk improvements, and quote the alternative market as leverage', fr: 'Développer une proposition technique intégrale : restructurer le programme, présenter un plan d\'amélioration des risques au client, négocier une augmentation échelonnée avec l\'assureur, et coter le marché alternatif comme levier' }, value: 100 }, { id: 'b', text: { es: 'Aceptar el 35% de aumento y convencer al cliente de que es el mejor resultado posible dado la siniestralidad', en: 'Accept the 35% increase and convince the client it is the best possible outcome given the loss ratio', fr: 'Accepter l\'augmentation de 35% et convaincre le client que c\'est le meilleur résultat possible' }, value: 10 }, { id: 'c', text: { es: 'Mover todo el programa a otra aseguradora que ofrezca un precio más bajo', en: 'Move the entire program to another insurer offering a lower price', fr: 'Transférer tout le programme à un autre assureur offrant un prix plus bas' }, value: 25 }, { id: 'd', text: { es: 'Reducir la comisión del corredor para absorber parte del incremento y mantener contento al cliente', en: 'Reduce the broker\'s commission to absorb part of the increase and keep the client happy', fr: 'Réduire la commission du courtier pour absorber une partie de l\'augmentation' }, value: 35 }], maxScore: 100, aiEvaluated: false, order: 3, isActive: true },
  // Networking
  { id: 'ins-broker-nw-01', profileId: 'insurance-broker-ceo', categoryId: 'ins-broker-soft-skills', competencyId: 'ins-broker-networking', type: 'open-text', content: { es: 'Describa cómo ha construido (o construiría) una red de relaciones estratégicas que genere negocios sostenibles para su correduría. Incluya su enfoque para: relaciones con C-suite de clientes corporativos, alianzas con otros intermediarios y bancos, presencia en asociaciones gremiales y eventos del sector, y desarrollo de relaciones con mercados internacionales de reaseguro y seguros especializados.', en: 'Describe how you have built (or would build) a strategic relationship network that generates sustainable business for your brokerage. Include your approach to: C-suite relationships with corporate clients, alliances with other intermediaries and banks, presence in trade associations and industry events, and developing relationships with international reinsurance and specialty insurance markets.', fr: 'Décrivez comment vous avez construit (ou construiriez) un réseau de relations stratégiques pour votre courtage. Incluez votre approche pour : les relations C-suite avec les clients, les alliances avec d\'autres intermédiaires et banques, la présence dans les associations professionnelles, et les relations avec les marchés internationaux de réassurance.' }, rubric: { es: 'Evaluar: (1) Estrategia sistemática de networking (no solo eventos sociales), (2) Enfoque diferenciado por tipo de relación (clientes, aseguradoras, reaseguradoras, colegas), (3) Capacidad de crear valor para los contactos (reciprocidad), (4) Uso de plataformas profesionales y eventos del sector, (5) Desarrollo de reputación y marca personal como líder del sector, (6) Métricas de conversión de relaciones en negocios concretos.', en: 'Evaluate: (1) Systematic networking strategy (not just social events), (2) Differentiated approach by relationship type (clients, insurers, reinsurers, peers), (3) Ability to create value for contacts (reciprocity), (4) Use of professional platforms and industry events, (5) Reputation and personal brand development as industry leader, (6) Relationship-to-business conversion metrics.', fr: 'Évaluer : (1) Stratégie de networking systématique, (2) Approche différenciée par type de relation, (3) Capacité à créer de la valeur, (4) Utilisation des plateformes et événements, (5) Développement de la réputation et marque personnelle, (6) Métriques de conversion.' }, maxScore: 100, aiEvaluated: true, order: 4, isActive: true },
  // Team Building (scale)
  { id: 'ins-broker-tb-02', profileId: 'insurance-broker-ceo', categoryId: 'ins-broker-soft-skills', competencyId: 'ins-broker-team-building', type: 'scale', content: { es: '¿Qué tan efectivo se considera construyendo y liderando equipos comerciales de alto rendimiento en la industria de intermediación de seguros?', en: 'How effective do you consider yourself at building and leading high-performance commercial teams in the insurance brokerage industry?', fr: 'Dans quelle mesure vous considérez-vous efficace pour construire et diriger des équipes commerciales de haute performance dans le courtage d\'assurance ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Experiencia limitada en gestión de equipos de corretaje', en: 'Limited brokerage team management experience', fr: 'Expérience limitée en gestion d\'équipes de courtage' }, max: { es: 'He construido múltiples equipos de alto rendimiento con resultados excepcionales', en: 'I have built multiple high-performance teams with exceptional results', fr: 'J\'ai construit de multiples équipes de haute performance avec des résultats exceptionnels' } }, maxScore: 100, aiEvaluated: false, order: 5, isActive: true },
];

export const insBrokerReadinessQuestions: Question[] = [
  // Digital Distribution
  { id: 'ins-broker-dd-01', profileId: 'insurance-broker-ceo', categoryId: 'ins-broker-readiness', competencyId: 'ins-broker-digital-distribution', type: 'scenario', content: { es: 'Una plataforma tecnológica de comparación de seguros (aggregator) ha comenzado a operar en su mercado, ofreciendo cotización y compra de seguros personales y PYME en línea con comisiones 50% más bajas que las del canal tradicional. En 8 meses ha capturado el 5% del mercado de seguros personales. Tres de sus ejecutivos junior más talentosos han renunciado para trabajar en la plataforma. Su cartera de seguros personales (35% de sus ingresos) está perdiendo clientes al ritmo del 3% mensual.\nContexto: Su sistema de gestión es un software de 12 años. El 80% de sus procesos son manuales. Su ventaja es la relación personal con el cliente y el expertise técnico en riesgos complejos.', en: 'A technology insurance comparison platform (aggregator) has entered your market, offering online quote and purchase for personal and SME insurance at 50% lower commissions than traditional channels. In 8 months it has captured 5% of the personal lines market. Three of your most talented junior executives have resigned to work at the platform. Your personal lines portfolio (35% of revenue) is losing clients at 3% monthly.\nContext: Your management system is 12-year-old software. 80% of processes are manual. Your advantage is personal client relationships and technical expertise in complex risks.', fr: 'Un agrégateur d\'assurance a commencé à opérer sur votre marché, offrant des commissions 50% inférieures. En 8 mois, il a capturé 5% du marché des assurances personnelles. Trois de vos jeunes talents ont démissionné. Votre portefeuille de lignes personnelles perd 3% de clients par mois.\nContexte : Votre système a 12 ans. 80% des processus sont manuels.' }, rubric: { es: 'Evaluar: (1) Estrategia de segmentación: digital para commodities vs. asesoría para riesgos complejos, (2) Plan de transformación tecnológica con timeline y presupuesto realistas, (3) Modelo híbrido de distribución (digital + presencial), (4) Estrategia de retención de talento y atracción de perfiles digitales, (5) Propuesta de valor diferenciada frente al aggregator, (6) Posible alianza con insurtechs en lugar de competir frontalmente.', en: 'Evaluate: (1) Segmentation strategy: digital for commodities vs. advisory for complex risks, (2) Technology transformation plan with realistic timeline and budget, (3) Hybrid distribution model (digital + in-person), (4) Talent retention and digital profile attraction strategy, (5) Differentiated value proposition vs. the aggregator, (6) Possible insurtech alliance instead of head-on competition.', fr: 'Évaluer : (1) Stratégie de segmentation : digital pour les commodités vs. conseil pour les risques complexes, (2) Plan de transformation technologique, (3) Modèle hybride de distribution, (4) Stratégie de rétention du talent, (5) Proposition de valeur différenciée, (6) Alliance possible avec des insurtechs.' }, maxScore: 100, aiEvaluated: true, order: 1, isActive: true },
  // Data Analytics
  { id: 'ins-broker-da-01', profileId: 'insurance-broker-ceo', categoryId: 'ins-broker-readiness', competencyId: 'ins-broker-data-analytics', type: 'multiple-choice', content: { es: 'Su correduría tiene 15 años de datos de siniestralidad, renovaciones y colocaciones de sus clientes, pero esta información está en hojas de Excel dispersas y en el conocimiento tácito de los ejecutivos senior. Un proveedor de tecnología le propone una plataforma de analytics por USD 200,000 anuales que analizaría estos datos para predecir renovaciones en riesgo, identificar oportunidades de cross-selling y optimizar la colocación en mercados. ¿Cuál es su decisión?', en: 'Your brokerage has 15 years of loss, renewal, and placement data for clients, but this information is in scattered Excel spreadsheets and in the tacit knowledge of senior executives. A technology vendor proposes an analytics platform for USD 200,000 annually that would analyze this data to predict at-risk renewals, identify cross-selling opportunities, and optimize market placement. What is your decision?', fr: 'Votre courtage a 15 ans de données de sinistralité et de renouvellements, mais ces informations sont dans des fichiers Excel dispersés. Un fournisseur propose une plateforme d\'analytics pour 200 000 USD par an. Quelle est votre décision ?' }, options: [{ id: 'a', text: { es: 'Invertir primero en consolidar y limpiar los datos existentes (3-6 meses), luego implementar la plataforma de analytics en fases comenzando con el caso de uso de mayor impacto (retención de clientes), y medir ROI antes de escalar', en: 'First invest in consolidating and cleaning existing data (3-6 months), then implement the analytics platform in phases starting with the highest-impact use case (client retention), and measure ROI before scaling', fr: 'Investir d\'abord dans la consolidation et le nettoyage des données (3-6 mois), puis implémenter la plateforme par phases en commençant par la rétention des clients, et mesurer le ROI avant d\'évoluer' }, value: 100 }, { id: 'b', text: { es: 'Contratar la plataforma inmediatamente y cargar todos los datos disponibles', en: 'Contract the platform immediately and load all available data', fr: 'Contracter la plateforme immédiatement et charger toutes les données disponibles' }, value: 25 }, { id: 'c', text: { es: 'Rechazar la inversión porque los ejecutivos senior conocen bien a sus clientes y eso es suficiente', en: 'Reject the investment because senior executives know their clients well and that is sufficient', fr: 'Rejeter l\'investissement car les cadres senior connaissent bien leurs clients' }, value: 10 }, { id: 'd', text: { es: 'Contratar un data scientist interno para construir una solución propia más económica', en: 'Hire an internal data scientist to build a more cost-effective proprietary solution', fr: 'Embaucher un data scientist interne pour construire une solution propriétaire plus économique' }, value: 35 }], maxScore: 100, aiEvaluated: false, order: 2, isActive: true },
  // New Markets
  { id: 'ins-broker-nm-01', profileId: 'insurance-broker-ceo', categoryId: 'ins-broker-readiness', competencyId: 'ins-broker-new-markets', type: 'open-text', content: { es: 'Identifique y analice tres oportunidades emergentes de mercado para una correduría de seguros en Latinoamérica y el Caribe que podrían generar nuevas fuentes de ingresos significativos en los próximos 5 años. Para cada oportunidad, describa: el tamaño estimado del mercado, las capacidades necesarias para capturarlo, los principales desafíos, y un plan de entrada al mercado.', en: 'Identify and analyze three emerging market opportunities for an insurance brokerage in Latin America and the Caribbean that could generate significant new revenue sources over the next 5 years. For each opportunity, describe: estimated market size, capabilities needed to capture it, main challenges, and a market entry plan.', fr: 'Identifiez et analysez trois opportunités de marché émergentes pour un courtage d\'assurance en Amérique latine et dans les Caraïbes qui pourraient générer de nouvelles sources de revenus significatives dans les 5 prochaines années. Pour chaque opportunité, décrivez : la taille estimée du marché, les capacités nécessaires, les principaux défis et un plan d\'entrée.' }, rubric: { es: 'Evaluar: (1) Identificación de oportunidades reales y relevantes (cyber, seguros paramétricos, insurtech, ESG, embedded insurance, salud digital, etc.), (2) Fundamentación con datos de mercado y tendencias, (3) Análisis realista de capacidades requeridas vs. existentes, (4) Planes de entrada al mercado concretos y ejecutables, (5) Comprensión de la dinámica competitiva en cada segmento, (6) Visión estratégica de cómo estas oportunidades transforman el modelo de negocio del corredor.', en: 'Evaluate: (1) Identification of real and relevant opportunities (cyber, parametric, insurtech, ESG, embedded insurance, digital health, etc.), (2) Market data and trend substantiation, (3) Realistic analysis of required vs. existing capabilities, (4) Concrete and executable market entry plans, (5) Understanding of competitive dynamics in each segment, (6) Strategic vision of how these opportunities transform the broker business model.', fr: 'Évaluer : (1) Identification d\'opportunités réelles et pertinentes, (2) Données de marché et tendances, (3) Analyse réaliste des capacités, (4) Plans d\'entrée concrets, (5) Dynamique concurrentielle, (6) Vision stratégique de transformation du modèle.' }, maxScore: 100, aiEvaluated: true, order: 3, isActive: true },
  // Digital Distribution (scale)
  { id: 'ins-broker-dd-02', profileId: 'insurance-broker-ceo', categoryId: 'ins-broker-readiness', competencyId: 'ins-broker-digital-distribution', type: 'scale', content: { es: '¿Qué tan preparado se considera para liderar la transformación digital de una correduría de seguros, incluyendo la implementación de plataformas digitales, automatización de procesos y adopción de modelos de distribución híbridos?', en: 'How prepared do you consider yourself to lead the digital transformation of an insurance brokerage, including implementing digital platforms, process automation, and hybrid distribution model adoption?', fr: 'Dans quelle mesure vous considérez-vous prêt à diriger la transformation digitale d\'un courtage d\'assurance, y compris l\'implémentation de plateformes digitales, l\'automatisation des processus et l\'adoption de modèles de distribution hybrides ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Conocimiento básico de herramientas digitales en corretaje', en: 'Basic knowledge of digital tools in brokerage', fr: 'Connaissance de base des outils numériques en courtage' }, max: { es: 'He liderado transformaciones digitales exitosas en intermediación de seguros', en: 'I have led successful digital transformations in insurance brokerage', fr: 'J\'ai dirigé des transformations numériques réussies dans le courtage d\'assurance' } }, maxScore: 100, aiEvaluated: false, order: 4, isActive: true },
];
